mapper.select:
SELECT r.review_id AS reviewId, a.appointment_id AS appointmentId, a.staff_id AS staffId, s.name AS staffName, a.customer_id AS customerId, c.name AS customerName, r.overall_rating AS overallRating, r.service_attitude_rating AS serviceAttitudeRating, r.professional_ability_rating AS professionalAbilityRating, r.service_quality_rating AS serviceQualityRating, r.review_content AS reviewContent, r.is_anonymous AS isAnonymous, r.create_time AS createTime, 1 AS reviewerRole, 2 AS reviewTarget FROM review r JOIN appointment a ON r.appointment_id = a.appointment_id JOIN staff s ON a.staff_id = s.staff_id JOIN customer_detail c ON a.customer_id = c.customer_id
AND a.staff_id = #{staffId}
AND a.appointment_id = #{appointmentId}
ORDER BY r.create_time DESC

SELECT e.review_extra_id AS reviewId, a.appointment_id AS appointmentId, a.staff_id AS staffId, s.name AS staffName, a.customer_id AS customerId, c.name AS customerName, e.overall_rating AS overallRating, NULL AS serviceAttitudeRating, NULL AS professionalAbilityRating, NULL AS serviceQualityRating, e.review_content AS reviewContent, 0 AS isAnonymous, e.create_time AS createTime, 2 AS reviewerRole, 2 AS reviewTarget FROM review_extra e JOIN appointment a ON e.appointment_id = a.appointment_id JOIN staff s ON a.staff_id = s.staff_id JOIN customer_detail c ON a.customer_id = c.customer_id WHERE e.reviewer_role = 2 AND e.review_target = 2
AND a.staff_id = #{staffId}
AND a.appointment_id = #{appointmentId}
ORDER BY e.create_time DESC
